customCSS:
/* Midnight Aurora - Northern Lights */
@import url('https://fonts.googleapis.com/css2?family=Exo+2:wght@300;400;600;700&family=Nunito:wght@300;400;600&family=Fira+Code&display=swap');

.cyber-grid {
  background: none;
  animation: none;
}

.cyber-glow {
  background: 
    radial-gradient(ellipse 800px 400px at 20% 0%, rgba(66, 230, 200, 0.1), transparent),
    radial-gradient(ellipse 600px 500px at 50% 10%, rgba(168, 110, 255, 0.08), transparent),
    radial-gradient(ellipse 700px 350px at 80% 5%, rgba(66, 230, 138, 0.06), transparent);
  animation: auroraShift 15s ease-in-out infinite;
}

@keyframes auroraShift {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.7; }
}

.stat-card {
  border: 1px solid rgba(66, 230, 200, 0.12);
  backdrop-filter: blur(10px);
}

.stat-card::before {
  background: linear-gradient(90deg, #42e6c8, #a86eff, #42e68a);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(66, 230, 200, 0.3);
  box-shadow: 0 4px 30px rgba(66, 230, 200, 0.15);
}

.stat-value {
  text-shadow: 0 0 20px currentColor;
}

.celebration-title {
  background: linear-gradient(135deg, #42e6c8, #a86eff, #42e68a);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(66, 230, 200, 0.08);
}

.miner-card:hover {
  border-color: rgba(168, 110, 255, 0.2);
}
